    private fun loadSortOrderFromConfig(col: com.ichi2.libanki.Collection) {
        val preferences = baseContext.sharedPrefs()
        if (cardsOrNotes == CARDS) {
            mOrder = SortType.fromCol(col.config, preferences)
            mOrderAsc = col.config.get("sortBackwards") ?: false
            return
        }

        val noteSortType = col.config.get<String>("noteSortType") ?: SortType.SORT_FIELD.ankiSortType
        val noteSort = SortType.entries.firstOrNull { it.ankiSortType == noteSortType } ?: SortType.SORT_FIELD
        mOrder = if (noteSort == SortType.SORT_FIELD && preferences.getBoolean(NOTE_BROWSER_NO_SORTING_KEY, false)) {
            SortType.NO_SORTING
        } else {
            noteSort
        }
        mOrderAsc = col.config.get("browserNoteSortBackwards") ?: false
    }

    private fun saveSortOrderToConfig(col: com.ichi2.libanki.Collection, which: SortType) {
        val preferences = baseContext.sharedPrefs()
        if (cardsOrNotes == CARDS) {
            which.save(col.config, preferences)
            col.config.set("sortBackwards", mOrderAsc)
            return
        }

        col.config.set("noteSortType", which.ankiSortType ?: SortType.SORT_FIELD.ankiSortType)
        preferences.edit {
            putBoolean(NOTE_BROWSER_NO_SORTING_KEY, which == SortType.NO_SORTING)
        }
        col.config.set("browserNoteSortBackwards", mOrderAsc)
    }

    private fun saveSortBackwardsToConfig(col: com.ichi2.libanki.Collection) {
        if (cardsOrNotes == CARDS) {
            col.config.set("sortBackwards", mOrderAsc)
        } else {
            col.config.set("browserNoteSortBackwards", mOrderAsc)
        }
    }
